qry:select.qry:xquery:
	for $r in sql('
	SELECT TTA04_NOVEDADES.oi_novedad,			
	TTA04_NOVEDADES.d_novedad,			
	TTA04_NOVEDADES.oi_personal_emp,
	TTA04_NOVEDADES.oi_tipohora,
	TTA04_NOVEDADES.f_fecinicio,
	TTA04_NOVEDADES.f_fecfin,
	TTA04_NOVEDADES.c_estado,
	ORG02_ESTRUC_PERS.oi_estructura,
	PER02_PERSONAL_EMP.e_numero_legajo,
	PER01_PERSONAL.d_ape_y_nom
	FROM ORG02_ESTRUC_PERS, PER02_PERSONAL_EMP, PER01_PERSONAL,
	TTA04_NOVEDADES
	JOIN ORG02_ESTRUC_PERS.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp,
	PER01_PERSONAL.oi_personal INNER PER02_PERSONAL_EMP.oi_personal,
	TTA04_NOVEDADES.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp
	WHERE ORG02_ESTRUC_PERS.oi_clase_org in ({%=string(#ORGANIGRAMAS:CLASES/CLASE/@oi_clase_org)%})
	{%? (#FILTRO:@f_desde != '') 
		{% AND (TTA04_NOVEDADES.f_fecinicio >= {DateTime(#FILTRO:@f_desde)} 
			 OR TTA04_NOVEDADES.f_fecfin >= {DateTime(#FILTRO:@f_desde)})
		%} 
		{%  %}   
	%}
	{%? (#FILTRO:@f_hasta != '') 
		{% AND (TTA04_NOVEDADES.f_fecinicio <= {DateTime(#FILTRO:@f_hasta)} 
			 OR TTA04_NOVEDADES.f_fecfin <= {DateTime(#FILTRO:@f_hasta)})
		%} 
		{%  %}   
	%}
  {%? (#FILTRO:@oi_empresa!='') 
		{% AND PER02_PERSONAL_EMP.oi_empresa={#FILTRO:@oi_empresa} %} 
		{% %} 
	%}
	{%? (#FILTRO:@c_estado!='') 
		{% AND TTA04_NOVEDADES.c_estado={#FILTRO:@c_estado} %} 
		{% %} 
	%}
  {%? (#FILTRO:@oi_localidad!='') 
		{% AND PER01_PERSONAL.oi_localidad={#FILTRO:@oi_localidad} %} 
		{% %} 
	%}
	{%? (#FILTRO:@oi_categoria!='') 
		{% AND PER02_PERSONAL_EMP.oi_categoria_ult={#FILTRO:@oi_categoria} %} 
		{% %} 
	%}
  {%? (string(#FILTRO:ESTRUCTURAS/ESTRUCTURA/@id)!='') 
		{% AND ORG02_ESTRUC_PERS.oi_estructura in ({%=string(#FILTRO:ESTRUCTURAS/ESTRUCTURA/@id)%}) %} 
		{%  %} 
	%}
	{%? (string(#FILTRO:PERSONAS/PERSONA/@id)!='') 
		{% AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=string(#FILTRO:PERSONAS/PERSONA/@id)%}) %} 
		{%  %} 
	%}
	{%? (string(#FILTRO:TIPOHORAS/TIPOHORA/@id)!='') 
		{% AND TTA04_NOVEDADES.oi_tipohora in ({%=string(#FILTRO:TIPOHORAS/TIPOHORA/@id)%}) %} 
		{%  %} 
	%}
	{%? (#FILTRO:@oi_convenio!='') 
		{% AND PER02_PERSONAL_EMP.oi_categoria_ult in
			(SELECT ORG18_CATEGORIAS.oi_categoria
			FROM ORG18_CATEGORIAS
			WHERE ORG18_CATEGORIAS.oi_convenio = {%=#FILTRO:@oi_convenio%}) 
		%} 
		{% %} 
	%}  
	ORDER BY oi_estructura ASC, e_numero_legajo ASC 
')/ROWS/ROW

	for $r in sql('
	SELECT TTA04_LICEN_PER.oi_licencia_per,
	TTA04_LICEN_PER.oi_personal_emp, 
	TTA04_LICEN_PER.c_estado,
	PER02_LICEN_PER.f_inicio,
	PER02_LICEN_PER.f_fin,
	PER16_LICENCIAS.oi_licencia,
	PER16_LICENCIAS.c_licencia,
	PER16_LICENCIAS.d_licencia,
	TTA01_TIPOHORAS.oi_tipohora,
	ORG02_ESTRUC_PERS.oi_estructura,
	PER02_PERSONAL_EMP.e_numero_legajo,
	PER01_PERSONAL.d_ape_y_nom			
	FROM ORG02_ESTRUC_PERS, PER02_PERSONAL_EMP, PER01_PERSONAL,
	TTA04_LICEN_PER, PER02_LICEN_PER,
	PER16_LICENCIAS, TTA01_TIPOHORAS
	JOIN TTA04_LICEN_PER.oi_licencia_per INNER  PER02_LICEN_PER.oi_licencia_per,
	PER02_LICEN_PER.oi_licencia INNER PER16_LICENCIAS.oi_licencia,
	PER16_LICENCIAS.oi_licencia INNER TTA01_TIPOHORAS.oi_licencia,			
	ORG02_ESTRUC_PERS.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp,
	PER01_PERSONAL.oi_personal INNER PER02_PERSONAL_EMP.oi_personal,
	TTA04_LICEN_PER.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp
	WHERE ORG02_ESTRUC_PERS.oi_clase_org in ({%=string(#ORGANIGRAMAS:CLASES/CLASE/@oi_clase_org)%})
	{%? (#FILTRO:@f_desde != '') 
		{% AND (PER02_LICEN_PER.f_inicio >= {DateTime(#FILTRO:@f_desde)} 
			 OR PER02_LICEN_PER.f_fin >= {DateTime(#FILTRO:@f_desde)})
		%} 
		{%  %}   
	%}
	{%? (#FILTRO:@f_hasta != '') 
		{% AND (PER02_LICEN_PER.f_inicio <= {DateTime(#FILTRO:@f_hasta)} 
			 OR PER02_LICEN_PER.f_fin <= {DateTime(#FILTRO:@f_hasta)})
		%} 
		{%  %}   
	%}
  {%? (#FILTRO:@oi_empresa!='') 
		{% AND PER02_PERSONAL_EMP.oi_empresa={#FILTRO:@oi_empresa} %} 
		{% %} 
	%}
	{%? (#FILTRO:@c_estado!='') 
		{% AND TTA04_LICEN_PER.c_estado={#FILTRO:@c_estado} %} 
		{% %} 
	%}
  {%? (#FILTRO:@oi_localidad!='') 
		{% AND PER01_PERSONAL.oi_localidad={#FILTRO:@oi_localidad} %} 
		{% %} 
	%}
	{%? (#FILTRO:@oi_categoria!='') 
		{% AND PER02_PERSONAL_EMP.oi_categoria_ult={#FILTRO:@oi_categoria} %} 
		{% %} 
	%}
  {%? (string(#FILTRO:ESTRUCTURAS/ESTRUCTURA/@id)!='') 
		{% AND ORG02_ESTRUC_PERS.oi_estructura in ({%=string(#FILTRO:ESTRUCTURAS/ESTRUCTURA/@id)%}) %} 
		{%  %} 
	%}
	{%? (string(#FILTRO:PERSONAS/PERSONA/@id)!='') 
		{% AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=string(#FILTRO:PERSONAS/PERSONA/@id)%}) %} 
		{%  %} 
	%}
	{%? (string(#FILTRO:TIPOHORAS/TIPOHORA/@id)!='') 
		{% AND TTA01_TIPOHORAS.oi_tipohora in ({%=string(#FILTRO:TIPOHORAS/TIPOHORA/@id)%}) %} 
		{%  %} 
	%}
	{%? (#FILTRO:@oi_convenio!='') 
		{% AND PER02_PERSONAL_EMP.oi_categoria_ult in
			(SELECT ORG18_CATEGORIAS.oi_categoria
			FROM ORG18_CATEGORIAS
			WHERE ORG18_CATEGORIAS.oi_convenio = {%=#FILTRO:@oi_convenio%}) 
		%} 
		{% %} 
	%}  
	ORDER BY oi_estructura ASC, e_numero_legajo ASC 
')/ROWS/ROW
